// JavaScript
import '@maersk-global/mds-components-core/mc-typeahead-multi-select';

import { apiService } from 'my-api-service';

const initData = [
  { value: 'Copenhagen', label: 'Copenhagen', sublabel: 'DK - Capital Region', id: 1 },
  { value: 'Stockholm', label: 'Stockholm', sublabel: 'SE - Stockholm County', id: 2 },
  { value: 'Oslo', label: 'Oslo', sublabel: 'NO - Oslo', id: 3 },
  { value: 'Berlin', label: 'Berlin', sublabel: 'DE - North Rhine-Westphalia', id: 4 },
  { value: 'London', label: 'London', sublabel: 'UK - Greater London', id: 5 },
  { value: 'Paris', label: 'Paris', sublabel: 'FR - Île-de-France', id: 6 },
  { value: 'Warsaw', label: 'Warsaw', sublabel: 'PL - Masovian Voivodeship', id: 7 },
];

const mcTypeahead = document.querySelector('mc-typeahead-multi-select');
mcTypeahead.addEventListener('optionselected', onOptionSelected);
mcTypeahead.addEventListener('search', setData);
mcTypeahead.data = initData;

const setData = async () => {
  mcTypeahead.loading = true;
  await apiService.search(event.target.value); 
  mcTypeahead.data = apiService.options ? [...apiService.options] : initData;
  mcTypeahead.loading = false;
}

const onOptionSelected = (event) => {
  mcTypeahead.data = initData;
};

